import numpy as np

def dpo_loss(log_pi_w: np.ndarray, log_pi_l: np.ndarray, log_ref_w: np.ndarray, log_ref_l: np.ndarray, beta: float) -> float:
    log_ratio_w = log_pi_w - log_ref_w
    log_ratio_l = log_pi_l - log_ref_l
    reward_diff = beta * (log_ratio_w - log_ratio_l)
    # log_sigmoid(x) = -softplus(-x) = x - log(1+exp(x)) for numerical stability
    # Using: log_sigmoid(x) = -log(1 + exp(-x))
    # Numerically stable: -log1p(exp(-clip(x, -30, ...)))
    log_sig = -np.log1p(np.exp(-np.clip(reward_diff, -30, 30)))
    return -float(np.mean(log_sig))

def implicit_reward(log_pi: np.ndarray, log_ref: np.ndarray, beta: float) -> np.ndarray:
    return beta * (log_pi - log_ref)
